const answers = $input.first().json.Answer || [];
const txtRecords = answers.filter(a => a.type === 16).map(a => a.data.replace(/\"/g, ''));
const spfRecord = txtRecords.find(r => r.includes('v=spf1'));
return [{ json: { spf_valid: !!spfRecord, spf_record: spfRecord || null, has_dangerous_all: spfRecord ? spfRecord.includes('+all') : false } }];

const answers = $input.first().json.Answer || [];
const txt = answers.filter(a => a.type === 16).map(a => a.data.replace(/\"/g, ''));
const dmarcRecord = txt.find(r => r.includes('v=DMARC1'));
return [{ json: { dmarc_valid: !!dmarcRecord, dmarc_record: dmarcRecord || null, policy: dmarcRecord ? (dmarcRecord.match(/p=(\w+)/)?.[1] || 'unknown') : null } }];

const answers = $input.first().json.Answer || [];
const mxRecords = answers.filter(a => a.type === 15).map(a => ({ priority: parseInt(a.data.split(' ')[0]), exchange: a.data.split(' ')[1] }));
return [{ json: { has_mx: mxRecords.length > 0, mx_count: mxRecords.length, mx_records: mxRecords } }];

const answers = $input.first().json.Answer || [];
const txt = answers.filter(a => a.type === 16).map(a => a.data.replace(/\"/g, ''));
const dkimRecord = txt.find(r => r.includes('v=DKIM1') || r.includes('p='));
return [{ json: { dkim_valid: !!dkimRecord, dkim_record: dkimRecord || null, selector_found: dkimRecord ? 'google' : null } }];

const spf = $('Parse SPF').first().json;
const dmarc = $('Parse DMARC').first().json;
const mx = $('Parse MX').first().json;
const dkim = $('Parse DKIM').first().json;
const domain = $('Split In Batches').first().json;

let status = 'healthy';
const issues = [];
if (!spf.spf_valid) { status = 'critical'; issues.push('SPF record missing'); }
if (spf.has_dangerous_all) { status = 'critical'; issues.push('SPF has +all (anyone can spoof)'); }
if (!dmarc.dmarc_valid) { if (status !== 'critical') status = 'warning'; issues.push('DMARC record missing'); }
if (dmarc.policy === 'none') { issues.push('DMARC policy is none (monitoring only)'); }
if (!dkim.dkim_valid) { if (status !== 'critical') status = 'warning'; issues.push('DKIM not found on common selectors'); }
if (!mx.has_mx) { status = 'critical'; issues.push('No MX records'); }

const result = { domain_id: domain.id, domain: domain.domain, overall_status: status, spf_valid: spf.spf_valid, spf_record: spf.spf_record, dkim_valid: dkim.dkim_valid, dkim_record: dkim.dkim_record, dmarc_valid: dmarc.dmarc_valid, dmarc_record: dmarc.dmarc_record, mx_records: mx.mx_records, blacklist_hits: [], issues, raw_results: { spf, dmarc, mx, dkim } };

const esc = (s) => s != null ? "'" + String(s).replace(/'/g, "''") + "'" : 'NULL';
result.store_sql = `INSERT INTO domain_checks (domain_id, spf_valid, spf_record, dkim_valid, dkim_record, dmarc_valid, dmarc_record, mx_records, blacklist_hits, overall_status, raw_results) VALUES (${result.domain_id}, ${result.spf_valid}, ${esc(result.spf_record)}, ${result.dkim_valid}, ${esc(result.dkim_record)}, ${result.dmarc_valid}, ${esc(result.dmarc_record)}, '${JSON.stringify(result.mx_records).replace(/'/g, "''")}'::jsonb, '[]'::jsonb, '${result.overall_status}', '${JSON.stringify(result.raw_results).replace(/'/g, "''")}'::jsonb) RETURNING id`;

return [{ json: result }];

const current = $('Determine Status').first().json;
const previous = $('Get Previous Check').first().json;

if (!previous || !previous.id) {
  return [{ json: { changed: true, is_first: true, alerts: [{ type: 'first_check', severity: 'info', message: `First check recorded for ${current.domain}` }], domain_id: current.domain_id } }];
}

const alerts = [];
if (previous.spf_valid && !current.spf_valid) alerts.push({ type: 'spf_missing', severity: 'critical', message: `SPF record removed from ${current.domain}` });
if (previous.dkim_valid && !current.dkim_valid) alerts.push({ type: 'dkim_failed', severity: 'warning', message: `DKIM validation failed for ${current.domain}` });
if (previous.dmarc_valid && !current.dmarc_valid) alerts.push({ type: 'dmarc_missing', severity: 'warning', message: `DMARC record removed from ${current.domain}` });
if (previous.overall_status !== current.overall_status) alerts.push({ type: 'status_change', severity: current.overall_status === 'critical' ? 'critical' : 'info', message: `${current.domain}: ${previous.overall_status} → ${current.overall_status}` });

return [{ json: { changed: alerts.length > 0, alerts, domain: current.domain, domain_id: current.domain_id } }];

const data = $input.first().json;
if (!data.alerts || data.alerts.length === 0) {
  return [{ json: { sql: 'SELECT 1', alert_count: 0 } }];
}
const values = data.alerts.map(a => `(${data.domain_id}, '${a.type}', '${a.message.replace(/'/g, "''")}', '${a.severity}')`).join(', ');
return [{ json: { sql: `INSERT INTO domain_alerts (domain_id, alert_type, message, severity) VALUES ${values}`, alert_count: data.alerts.length } }];
